INSERT INTO journal_articles (title, slug, excerpt, content, category, author, tags, is_published, is_featured, read_time_minutes) VALUES
('Nathalie Ziegler: Capturing Light in Gravity-Defying Glass', 'nathalie-ziegler-capturing-light-gravity-defying-glass', 'Born in Paris in 1970, daughter of an aeronautical engineer. Self-taught glass sculptor whose gravity-defying works have been shown internationally since her 2002 debut at Maison et Objet.', '## Perched, Suspended, Always Higher

Nathalie Ziegler (b. 1970, Paris), daughter of an aeronautical engineer, is self-taught in glass sculpture. She launched her first collection for Arums in 2002 at Maison et Objet. Known for enchanting, gravity-defying works spun from glass and light. Represented by Twenty First Gallery and Galerie Mougin. International presentations across galleries, fairs, and private residences.', 'designer_interview', 'Maison Affluency', '{"Nathalie Ziegler","Glass Art","Paris","Maison et Objet"}', false, false, 2),
('Olivia Cognet: Sculpting the Boundaries of Art and Design', 'olivia-cognet-sculpting-boundaries-art-design', 'French sculptor based in Vallauris, the city of clay. From Nice to Paris to Los Angeles, she draws inspiration from Picasso and Roger Capron. Represented by The Future Perfect.', '## The Balance Between Art and Design

> "I am constantly trying to find the perfect balance between Art and Design."

From Nice to Paris, via Los Angeles, Olivia Cognet settled in Vallauris — the city of clay. She draws inspiration from the masters of the Vallauris school: Picasso and Roger Capron. Represented by The Future Perfect. Her work explores all scales, far from convention, driven by passion for sculpture and architecture.', 'designer_interview', 'Maison Affluency', '{"Olivia Cognet","Ceramic Art","Vallauris","The Future Perfect","Sculpture"}', false, false, 2),
('Emmanuel Levet Stenne: The Warm Glow of Alabaster', 'emmanuel-levet-stenne-warm-glow-alabaster', 'French designer specializing in alabaster lighting. Represented by Galerie Carole Decombe and The Invisible Collection.', '## Light Through Stone

Emmanuel Levet Stenne is a French designer who transforms alabaster and onyx into ethereal lighting fixtures. His wall lamps, pendants, sconces, and coffee tables are celebrated for their warm, natural glow. Represented by Galerie Carole Decombe in Paris and sold through The Invisible Collection.', 'designer_interview', 'Maison Affluency', '{"Emmanuel Levet Stenne","Alabaster","Lighting","French Design"}', false, false, 2),
('Entrelacs Creation: Bronze and Alabaster, Minimalism and Mastery', 'entrelacs-creation-bronze-alabaster-minimalism', 'Family foundry in central France since 1982. Yves Macheret, with brother Paul, crafts minimal bronze and alabaster lighting.', '## A Family Craft Since 1982

Entrelacs is rooted in Fonderie d''Art Macheret, a family foundry in central France active since 1982. Yves Macheret, running the foundry with brother Paul since 2015, trained alongside his father in modelling, mould-making, casting, chasing, and patination.

His vision: minimal lighting designs at accessible prices, expressing the beauty and simplicity of bronze and alabaster. Collections include Ghost, Hublot, and Beam. The foundry employs 19 staff with 30+ years of experience.', 'designer_interview', 'Maison Affluency', '{"Entrelacs","Yves Macheret","Bronze","Alabaster","French Foundry","Lighting"}', false, false, 2),
('Garnier & Linker: Art and Craft in Contemporary Design', 'garnier-linker-art-craft-contemporary-design', 'Guillaume Garnier and Florent Linker met at École Camondo, worked at Studio KO and India Mahdavi respectively, then founded their duo in 2015.', '## From Camondo to Lost-Wax Crystal

Guillaume Garnier and Florent Linker met at École Camondo in Paris, graduating in 2012. They worked respectively at Studio KO and India Mahdavi before founding their duo in 2015.

All pieces are handmade in small series by French master craftsmen using lost-wax crystal and bronze processes. Represented by Maison Gerard (NYC) and Théorème Editions.

> Objects comfortable "in a gallery as in a private home."', 'designer_interview', 'Maison Affluency', '{"Garnier & Linker","Lost-Wax Crystal","French Design","École Camondo","Maison Gerard"}', false, false, 2),
('Emmanuel Babled: The Osmosis of Murano Glass and Marble', 'emmanuel-babled-osmosis-murano-glass-marble', 'French-Italian designer whose Osmosi series fuses Murano blown glass with marble through an innovative scanning and routing technique.', '## Virtual Fusion

Emmanuel Babled''s Osmosi series (2013–2014) achieves a virtual fusion between marble and Murano glass. The technique: glass is blown by a glassblower, scanned, and the negative shape routed out of stone. Limited editions of 6 + 1 AP. Babled Editions is his publishing label. He also published the monograph "La Main des Autres."', 'designer_interview', 'Maison Affluency', '{"Emmanuel Babled","Murano Glass","Marble","Osmosi","Limited Edition"}', false, false, 2),
('Léo Sentou: The Contemporary Classicist', 'leo-sentou-contemporary-classicist', 'French designer educated at ENSAAMA and Central Saint Martins. A self-described "contemporary classicist" inspired by 18th-century French furniture.', '## Elegance Means Elimination

> "I feel I''m a contemporary classicist — if such a term can be employed."

Léo Sentou studied at ENSAAMA Olivier de Serres in Paris and Central Saint Martins in London. Captivated since childhood by 18th-century French furniture, his collection honors tradition while remaining modern. Materials: limed oak, wrought iron, bronze, mohair, linen, lacquer. Pieces named with initials (L.D. Armchair, J.B.B Chair). Sold via The Invisible Collection. Based in London.', 'designer_interview', 'Maison Affluency', '{"Léo Sentou","Contemporary Classicist","French Furniture","Central Saint Martins","The Invisible Collection"}', false, false, 2),
('Atelier Février: Hand-Knotted Luxury from Nepal', 'atelier-fevrier-hand-knotted-luxury-nepal', 'Founded 2015 in Toulouse by Florian Pretet and Lisa Mukhia Pretet. Luxurious rugs hand-knotted in Nepal with Label STEP fair trade certification.', '## Contemporary Art Meets Traditional Craft

Founded in 2015 in Toulouse, Atelier Février is headed by Florian Pretet (creative director, Parisian Fashion School graduate) and Lisa (Isha) Mukhia Pretet. Each signature pattern is hand-drawn, scaled up, and hand-knotted by expert weavers in Nepal.

Label STEP certified (fair trade). One-of-a-kind color palettes and original cutouts. Sold via The Invisible Collection, featured on Architonic and Salon Design.', 'designer_interview', 'Maison Affluency', '{"Atelier Février","Hand-Knotted Rugs","Nepal","Textile Art","Fair Trade"}', false, false, 2),
('Atelier Pendhapa: Cross-Cultural Craftsmanship', 'atelier-pendhapa-cross-cultural-craftsmanship', 'Founded 2019 by Antonin Hautefort (French) and Ignatio Tenggara (Indonesian). Met at the AA School in London. Named Designer of the Day by Surface.', '## Evocative Spaces

Founded in 2019 by Antonin Hautefort (French) and Ignatio Tenggara (Indonesian/Singaporean), who met at The Architectural Association School of Architecture in London.

> "Our overarching mission revolves in engaging the human experience to create evocative spaces pushing the boundaries of craftsmanship."

AKAR collection created in collaboration with Métaphores (Hermès textile division). Named "Designer of the Day" by Surface Magazine. London and Singapore-based. Sold via The Invisible Collection and Studio Twenty Seven.', 'designer_interview', 'Maison Affluency', '{"Atelier Pendhapa","Indonesian Craftsmanship","AA School","Métaphores","Surface Magazine"}', false, false, 2),
('Man of Parts: Curating Global Design', 'man-of-parts-curating-global-design', 'Hamburg-based brand founded by Stephan Weishaupt, co-founder of Avenue Road. Commissions from Yabu Pushelberg, Sebastian Herkner, and Philippe Malouin.', '## A Way of Living

Man of Parts, founded by Stephan Weishaupt (co-founder of Avenue Road), commissions furniture, lighting and textiles from leading designers: Yabu Pushelberg, Sebastian Herkner, Philippe Malouin, Osvaldo Tenório, Simone Coste, Workshop/APD.

Featured in Wallpaper, AD Magazin Germany, Design Milk. Brand identity by Underline Studio. A global design collection bridging gallery and home.', 'designer_interview', 'Maison Affluency', '{"Man of Parts","Stephan Weishaupt","Yabu Pushelberg","Sebastian Herkner","Global Design"}', false, false, 2)
